{
  "customer_summary": {
    "summary": "The UVZ web application currently runs on Angular 18 and Pattern Library 11.3.1. Security support for Angular 18 ends on 21‑Nov‑2025, after which no free patches are provided. To keep the system safe and compliant, the client must move to a supported stack. Upgrading to Angular 19 and Pattern Library 12.6.0 restores security updates, aligns with the vendor’s roadmap, and prevents the need for costly “Never‑Ending Support” contracts. If the upgrade is not performed, the application will become vulnerable to unpatched security issues and may eventually violate internal compliance policies.",
    "impact_level": "medium",
    "is_bug": false,
    "workaround": "Continue on Angular 18 only by purchasing Never‑Ending Support from the vendor, which incurs additional cost and does not solve the underlying deprecation of the framework.",
    "eta_category": "medium"
  },
  "developer_context": {
    "big_picture": "UVZ is a client‑facing, browser‑based portal built with Angular. It is used by internal staff and external partners to access business services. The portal’s UI is assembled from the in‑house Pattern Library (PL) and third‑party UI components. This task upgrades the front‑end framework from Angular 18 (now out of security support) to Angular 19 and updates the Pattern Library to 12.6.0, together with all dependent UI libraries. The upgrade is required now because the security support window for Angular 18 closes in November 2025; without it the application would be exposed to unpatched vulnerabilities and could breach compliance. If the upgrade is postponed, the team would have to pay for a special support contract or risk operating an insecure system.",
    "scope_boundary": "IN: All front‑end code in the presentation container – Angular core, Angular CLI, TypeScript configuration, Pattern Library integration, UI component libraries (ng‑bootstrap, ng‑select, ag‑grid), Node.js version, and the vertical action bar usage. OUT: Back‑end Java services, database schema, infrastructure (servers, CI/CD pipelines unless they directly build the Angular app), non‑UI business logic, and any feature flags unrelated to UI rendering.",
    "classification_assessment": "",
    "classification_confidence": -1,
    "affected_components": [
      "Angular Core (presentation)",
      "Pattern Library Integration (presentation)",
      "UI Modules (presentation)",
      "Vertical Action Bar Component (presentation)",
      "ng-bootstrap Wrapper (presentation)",
      "ng-select Wrapper (presentation)",
      "ag-grid Wrapper (presentation)"
    ],
    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 18 LTS reached end‑of‑security‑support on 21‑Nov‑2025; continuing to run it would leave the portal without security patches. The upgrade to Angular 19 is therefore mandatory to stay within a supported lifecycle.",
        "severity": "blocking",
        "source_facts": ["tech_versions.json: Angular 18-lts"]
      },
      {
        "category": "dependency_risk",
        "boundary": "Third‑party UI libraries (ng‑bootstrap, ng‑select, ag‑grid) must have versions compatible with Angular 19. Some of the listed packages may only support Angular 18, so version mismatches could cause compile‑time or runtime errors.",
        "severity": "caution",
        "source_facts": ["Issue description: ng-bootstrap, ng-select, ag-grid-angular, ag-grid-community"]
      },
      {
        "category": "pattern_library_version",
        "boundary": "Pattern Library 12.6.0 deprecates the vertical action bar after PL 13.2.0 but still supports it now. The upgrade must ensure the vertical action bar continues to function and that any removed components are cleaned up.",
        "severity": "info",
        "source_facts": ["Issue description: vertical action bar usage"]
      },
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 requires at least Node.js 18.x and TypeScript 5.2+. The current stack (Node.js version not listed, TypeScript 4.9.5) may need to be bumped, otherwise the build will fail.",
        "severity": "caution",
        "source_facts": ["tech_versions.json: TypeScript 4.9.5", "issue description: node.js"]
      }
    ],
    "architecture_notes": "The UVZ system is split into five containers. The front‑end container (named *uvz‑frontend* in the architecture) hosts the presentation layer (≈287 components). Within this container, the Angular application is the core of the presentation layer. It imports the Pattern Library (PL) as a shared UI component library and wraps third‑party UI packages (ng‑bootstrap, ng‑select, ag‑grid). The Angular app communicates with back‑end services via HTTP APIs (application layer). The vertical action bar is a UI component provided by the Pattern Library and used across many pages. Upgrading Angular and PL therefore touches the core Angular module, the shared UI component modules, and the build pipeline (Webpack + Angular CLI). All downstream components (page modules, feature modules) will be affected because they depend on the upgraded core APIs.",
    "anticipated_questions": [
      {
        "question": "Which Node.js and TypeScript versions are required for Angular 19?",
        "answer": "Angular 19 officially supports Node.js 18 LTS and TypeScript 5.2+. The current project uses TypeScript 4.9.5, so the TypeScript version will need to be upgraded. The exact Node.js version used in the repo should be checked in the CI configuration and bumped if it is below 18."
      },
      {
        "question": "Are there breaking changes in Angular 19 that could affect our existing code?",
        "answer": "Angular 19 introduces stricter type checking, updates to RxJS, and deprecates several APIs that were still present in Angular 18. Existing components that rely on deprecated APIs (e.g., certain lifecycle hooks or deprecated CDK modules) will need to be refactored. The vertical action bar remains usable until PL 13.2.0, but any direct usage of removed PL 11 components must be removed."
      },
      {
        "question": "Do the UI libraries (ng‑bootstrap, ng‑select, ag‑grid) have compatible releases for Angular 19?",
        "answer": "Each library must be checked against its npm release notes. Most have released Angular‑19‑compatible versions, but the exact version ranges need to be verified and the package.json updated accordingly. If a library does not yet support Angular 19, a temporary fork or alternative may be required."
      },
      {
        "question": "Will the existing unit and e2e tests still run after the upgrade?",
        "answer": "Tests written with Karma, Jasmine, and Playwright target Angular 18 APIs. After the upgrade, compilation may fail if tests import deprecated symbols. Tests should be run after the upgrade to identify failures; updating test configurations (e.g., tsconfig for newer TypeScript) may be necessary."
      },
      {
        "question": "Is any change needed in the CI/CD pipeline (Webpack, Angular CLI) for the new versions?",
        "answer": "Angular CLI 19 will replace the current CLI 18. The Webpack configuration may need adjustments because Angular now uses the built‑in build system. The pipeline scripts that invoke `ng build` should be updated to the new CLI version, and any custom Webpack plugins should be verified for compatibility."
      }
    ],
    "linked_tasks": [
      "UVZUSLNVV-5824 (this upgrade ticket)",
      "BNUVZ-12529 (analysis comment \"how to get to angular 21\")"
    ]
  }
}

{
  "customer_summary": {
    "summary": "The frontend of the application is being upgraded to Angular 19. As part of this upgrade the SASS compiler that is used by the Angular build process must be switched to the new Angular‑Builder implementation (@angular-devkit/build-angular:application). The current compiler is deprecated and will no longer be supported in Angular 19, so without the migration future builds could fail or produce incorrect CSS, leading to visual regressions for end‑users. Performing the migration now, together with the recommended extra testing, ensures a smooth upgrade path and avoids regressions after the Angular version bump.",
    "impact_level": "medium",
    "is_bug": false,
    "workaround": "",
    "eta_category": "medium"
  },
  "developer_context": {
    "big_picture": "We run a large Angular front‑end (presentation layer) that is part of a multi‑container system serving internal and external users via a web portal. The UI is built with Angular 18 LTS, Angular CLI 18, Webpack 5 and a custom SASS styling pipeline. The upcoming Angular 19 release removes the old SASS loader and requires the new Angular‑Builder compiler. This task prepares the front‑end for the framework upgrade, preventing build breakage and visual regressions that would affect all users of the portal. The migration is timed with the broader Angular 19 upgrade, so delaying it would block the framework update and increase technical debt.",
    "scope_boundary": "IN: All build‑time configuration files (angular.json, tsconfig.json, any custom webpack config), SASS import statements, style‑library packages, CI/CD build scripts that invoke the Angular build, and related unit‑test configuration (Karma, Playwright) that compile styles. OUT: Application business logic, backend services, domain‑layer components, existing UI component code that does not touch SASS imports, and any non‑Angular parts of the system.",
    "classification_assessment": "",
    "classification_confidence": -1,
    "affected_components": [
      "Angular Build Configuration (presentation)",
      "Frontend CI Build Pipeline (infrastructure)"
    ],
    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 deprecates the legacy sass-loader and mandates the use of @angular-devkit/build-angular:application as the SASS compiler. All build scripts and angular.json entries that reference the old compiler must be updated, otherwise the build will fail or produce incorrect CSS.",
        "severity": "caution",
        "source_facts": [
          "tech_versions.json: Angular 18‑lts",
          "tech_versions.json: Angular CLI 18‑lts",
          "ADR: https://wiki.bnotk.de/spaces/UVZUSLNAS/pages/386958007/UVZ-09-ADR-003+-+Frontend+Build+Strategy+SASS+Import+Deprecation"
        ]
      },
      {
        "category": "dependency_risk",
        "boundary": "Any npm packages that provide SASS utilities (e.g., node‑sass, sass, sass‑loader) may be incompatible with the new Angular‑Builder compiler. Their versions need to be verified and possibly upgraded before the migration.",
        "severity": "info",
        "source_facts": [
          "dependencies.json: @angular/common v18‑lts",
          "dependencies.json: @angular/core v18‑lts"
        ]
      },
      {
        "category": "testing_constraint",
        "boundary": "The issue explicitly states that additional testing is required to minimise regression risk. All unit‑tests (Karma) and end‑to‑end tests (Playwright) that compile SASS must be re‑run after the migration.",
        "severity": "caution",
        "source_facts": [
          "Issue description: \"additional testing may be necessary to minimize the risk of potential regressions\""
        ]
      },
      {
        "category": "infrastructure_constraint",
        "boundary": "The CI/CD pipeline currently invokes the Angular build via scripts that assume the old compiler. Those scripts must be updated to use the new builder and the pipeline must be validated on the supported Node/Gradle versions.",
        "severity": "info",
        "source_facts": [
          "tech_versions.json: Gradle 8.2.1",
          "tech_versions.json: Node version implied by Angular CLI 18"
        ]
      }
    ],
    "architecture_notes": "WALKTHROUGH: The front‑end lives in its own container (the *Frontend* container) and belongs to the **presentation** layer. The primary component involved is the **Angular Build System** (a configuration component that lives in the presentation layer but touches the infrastructure layer via CI scripts). It consumes style assets from the **Shared Style Library** component (also presentation) and produces compiled CSS that is bundled into the static assets served by the **Web Server** component in the *Infrastructure* container. Neighbouring components include the **Component Library** (Angular Material, CDK) and the **Theme Service** that provides runtime theming. The migration will only touch the build‑system component and its interfaces to the CI pipeline; all downstream UI components remain unchanged.",
    "anticipated_questions": [
      {
        "question": "Do any SASS files need to be rewritten because of the new compiler?",
        "answer": "The new Angular‑Builder compiler drops support for the deprecated `@import` syntax that was allowed by the old loader. Review the ADR for the list of prohibited patterns and update any SASS files that use them."
      },
      {
        "question": "Will the migration affect the CI/CD build process?",
        "answer": "Yes. The build scripts that call `ng build` must be updated to use the new builder configuration. Verify that the CI environment uses a Node version compatible with Angular 19 and that Gradle steps are unchanged."
      },
      {
        "question": "Are there known compatibility issues with Angular Material or other UI libraries?",
        "answer": "Angular 19 is compatible with the latest versions of Angular Material and CDK. Ensure that the project upgrades those packages to the matching 19.x releases after the SASS migration."
      },
      {
        "question": "Do we need to adjust unit‑tests or e2e tests?",
        "answer": "All tests that compile styles (Karma unit tests and Playwright e2e tests) should be re‑run after the migration. No test code changes are expected unless a test relies on the old import syntax."
      },
      {
        "question": "What is the fallback if the migration breaks the build?",
        "answer": "Keep the previous `angular.json` configuration in version control. If the new build fails, you can revert to the old configuration and postpone the migration while investigating the cause."
      }
    ],
    "linked_tasks": [
      "UVZUSLNVV-5890 (Angular 19 upgrade ticket)",
      "UVZ-09-ADR-003 (Frontend Build Strategy SASS Import Deprecation)"
    ]
  }
}

